CREATE TABLE normalized.OperatingHoursTimes(operating_hours_time_key INTEGER PRIMARY KEY, operating_hours_key INTEGER DEFAULT(0) NOT NULL, day_of_week INTEGER, day_start_hour INTEGER, day_end_hour INTEGER, day_start_minute INTEGER, day_end_minute INTEGER, descriptive_time VARCHAR DEFAULT('') NOT NULL, specific_day DATE, created_dt TIMESTAMP DEFAULT(CURRENT_TIMESTAMP) NOT NULL, updated_dt TIMESTAMP DEFAULT(CURRENT_TIMESTAMP) NOT NULL, CHECK(((day_of_week >= 1) AND (day_of_week <= 7))), CHECK(((day_start_hour >= 0) AND (day_start_hour <= 23))), CHECK(((day_end_hour >= 0) AND (day_end_hour <= 23))), CHECK(((day_start_minute >= 0) AND (day_start_minute <= 59))), CHECK(((day_end_minute >= 0) AND (day_end_minute <= 59))), FOREIGN KEY (operating_hours_key) REFERENCES normalized.OperatingHours(operating_hours_key));;
