CREATE VIEW google.v_addresses AS SELECT id, googlePlaceId, COALESCE("nullif"(postalCode, ''), regexp_extract(formattedAddress, '([0-9]{5}(-[0-9]{4})?)', 1), '') AS postal_code, COALESCE(locality, '') AS city, COALESCE(administrativeArea, '') AS state_abbre, COALESCE(state, '') AS state, CASE  WHEN ((main."trim"(COALESCE(regionCode, '')) = '')) THEN ('###') ELSE regionCode END AS country_code, 'Physical' AS "type", COALESCE(CASE  WHEN ((COALESCE(array_length(addressLines), 0) = 0)) THEN (shortFormattedAddress) ELSE addressLines[1] END, '') AS address_line_1, COALESCE(CASE  WHEN ((array_length(addressLines) >= 2)) THEN (addressLines[2]) ELSE NULL END, '') AS address_line_2, COALESCE(CASE  WHEN ((array_length(addressLines) >= 3)) THEN (addressLines[3]) ELSE NULL END, '') AS address_line_3 FROM google.places;;
CREATE VIEW google.v_contact_phones AS SELECT id, googlePlaceId, nationalPhoneNumber AS phone_number, 'Primary Google Listed Number' AS "type" FROM google.places WHERE ((nationalPhoneNumber IS NOT NULL) AND (nationalPhoneNumber != ''));;
CREATE VIEW google.v_location_types AS SELECT DISTINCT primaryType AS location_type FROM google.places WHERE ((primaryType IS NOT NULL) AND (primaryType != ''));;
CREATE VIEW google.v_media AS SELECT id, googlePlaceId, authorDisplayName AS credit, split_part(googlePhotoName, '/', 4) AS title, concat('https://places.googleapis.com/v1/', googlePhotoName, '/media') AS url, widthPx AS width, heightPx AS height, 'Photo' AS media_type FROM google.photos;;
CREATE VIEW google.v_operating_hours AS SELECT DISTINCT googlePlaceId, 'Regular' AS "name", 'Google Regular Operating Hours' AS description, 'Regular' AS "type" FROM google.operating_hours WHERE (hoursType != 'current');;
CREATE VIEW google.v_operating_hours_times AS SELECT id, googlePlaceId, CASE  WHEN ((hoursType = 'regular')) THEN ('Regular') ELSE 'Exception' END AS "type", CASE  WHEN ((dayOfWeek = 0)) THEN (7) ELSE dayOfWeek END AS day_of_week, openHour AS day_start_hour, openMinute AS day_start_minute, closeHour AS day_end_hour, closeMinute AS day_end_minute, specificDate AS specific_day, CASE  WHEN (((openHour = 0) AND (openMinute = 0) AND (closeHour = 0) AND (closeMinute = 0))) THEN ('All Day') WHEN ((openHour IS NOT NULL)) THEN (((((((((((lpad(CAST(CASE  WHEN (((openHour % 12) = 0)) THEN (12) ELSE (openHour % 12) END AS VARCHAR), 2, '0') || ':') || lpad(CAST(openMinute AS VARCHAR), 2, '0')) || ' ') || CASE  WHEN ((openHour >= 12)) THEN ('PM') ELSE 'AM' END) || ' - ') || lpad(CAST(CASE  WHEN (((closeHour % 12) = 0)) THEN (12) ELSE (closeHour % 12) END AS VARCHAR), 2, '0')) || ':') || lpad(CAST(closeMinute AS VARCHAR), 2, '0')) || ' ') || CASE  WHEN ((closeHour >= 12)) THEN ('PM') ELSE 'AM' END)) ELSE 'Closed or UNKNOWN' END AS descriptive_time FROM google.operating_hours WHERE (hoursType != 'current');;
CREATE VIEW google.v_places AS SELECT primaryDisplayName AS "name", 4 AS data_source_key, googlePlaceId AS orig_data_source_key, id AS migration_primary_key, latitude, longitude, geminiGenerativeSummary AS ai_generative_description, editorialSummary AS description, administrativeArea AS state_abbre, state, primaryType AS location_type, to_json(struct_pack(google_name := googleName, business_status := businessStatus, good_for_children := goodForChildren, allow_dogs := allowDogs, accept_credit_cards := acceptCreditCards, accept_debit_cards := acceptDebitCards, accept_cash_only := acceptCashOnly, free_parking_lot := freeParkingLot, paid_parking_lot := paidParkingLot, free_street_parking := freeStreetParking, wheelchair_accessible_parking := wheelchairAccessibleParking, wheelchair_accessible_seating := wheelchairAccessibleSeating, search_api_type := CASE  WHEN ((statePark = CAST('t' AS BOOLEAN))) THEN ('State Park') WHEN ((stateForest = CAST('t' AS BOOLEAN))) THEN ('State Forest') WHEN ((stateWayside = CAST('t' AS BOOLEAN))) THEN ('State Wayside') WHEN ((nationalForest = CAST('t' AS BOOLEAN))) THEN ('National Forest') WHEN ((countyPark = CAST('t' AS BOOLEAN))) THEN ('County Park') WHEN ((naturalWildlifeArea = CAST('t' AS BOOLEAN))) THEN ('Natural Wildlife Area') WHEN ((cityPark = CAST('t' AS BOOLEAN))) THEN ('City Park') ELSE 'UNKNOWN' END)) AS attributes, nationalPhoneNumber AS phone, websiteUri AS website_url FROM google.places;;
CREATE VIEW google.v_websites AS (SELECT id, googlePlaceId, websiteUri AS website_url, 'Primary Google URL' AS description, 'Primary' AS "type" FROM google.places WHERE ((websiteUri IS NOT NULL) AND (websiteUri != ''))) UNION ALL (SELECT id, googlePlaceId, googleMapsUri AS website_url, 'Google Map Url' AS description, 'Directions' AS "type" FROM google.places WHERE ((googleMapsUri IS NOT NULL) AND (googleMapsUri != '')));;
CREATE VIEW mn_dnr.v_locations AS SELECT "0" AS "name", 'MN' AS state_abbre, 'Minnesota' AS state, 'State Park' AS location_type, 2 AS data_source_key, ('DNR_PDF_' || "0") AS orig_data_source_key, NULL AS migration_primary_key, 0.0 AS latitude, 0.0 AS longitude, '' AS description, to_json(struct_pack(winter_camping := (main."trim"("3") = '•'), spring_camping := (main."trim"("4") = '•'), summer_camping := (main."trim"("5") = '•'), fall_camping := (main."trim"("6") = '•'), site_drive_in := (main."trim"("7") = '•'), site_accessible_drive_in := (main."trim"("8") = '•'), max_rv_length := "9", rv_pull_through_sites := (main."trim"("10") = '•'), "30_amp_hookup_sites" := (main."trim"("11") = '•'), "50_amp_hookup_sites" := (main."trim"("12") = '•'), horse_campsites := (main."trim"("13") = '•'), backpack_sites := (main."trim"("14") = '•'), group_campsites := (main."trim"("15") = '•'), has_showers := (main."trim"("16") = '•'), has_accessible_showers := (main."trim"("17") = '•'), has_flush_toilets := (main."trim"("18") = '•'), has_accessible_flush_toilets := (main."trim"("19") = '•'), has_dump_station := (main."trim"("20") = '•'), camper_cabins := (main."trim"("21") = '•'), accessible_camper_cabins := (main."trim"("22") = '•'), other_lodging := (main."trim"("23") = '•'), hiking_trails := (main."trim"("24") = '•'), paved_trails := (main."trim"("25") = '•'), groomed_cross_country_ski_trails := (main."trim"("26") = '•'), swimming_beach := (main."trim"("27") = '•'), fishing_pier := (main."trim"("28") = '•'), accessible_fishing_pier := (main."trim"("29") = '•'), boat_rental := (main."trim"("30") = '•'), showshoe_rental := (main."trim"("31") = '•'), picnic_shelter := (main."trim"("32") = '•'), accessible_picnic_shelter := (main."trim"("33") = '•'), nature_programs := (main."trim"("34") = '•'), accessible_track_chair := (main."trim"("35") = '•'))) AS attributes FROM mn_dnr.extracted_table_0 WHERE (("0" != '') AND ("0" !~~ '%NAME OF STATE PARK%'));;
CREATE VIEW mn_dnr.v_location_types AS SELECT DISTINCT 'State Park' AS location_type FROM mn_dnr.extracted_table_0 WHERE (("0" IS NOT NULL) AND (length("0") > 3) AND ("0" !~~ 'Page %'));;
CREATE VIEW mn_gis.v_boundary_locations AS SELECT AREA_NAME AS "name", st_x(st_centroid(st_transform(geom, 'EPSG:26915', 'EPSG:4326'))) AS latitude, st_y(st_centroid(st_transform(geom, 'EPSG:26915', 'EPSG:4326'))) AS longitude, 'MN' AS state_abbre, 'Minnesota' AS state, AREA_TYPE AS location_type, 7 AS data_source_key, CAST(OGC_FID AS VARCHAR) AS orig_data_source_key, OGC_FID AS migration_primary_key, to_json(struct_pack(gis_acres := GIS_ACRES, legislative_id := LEGISLATIV, program_project := PGRM_PROJE, guid := GUID)) AS attributes FROM mn_gis.dnr_stat_plan_areas_prk;;
CREATE VIEW mn_gis.v_boundary_location_types AS SELECT DISTINCT AREA_TYPE AS location_type FROM mn_gis.dnr_stat_plan_areas_prk WHERE (AREA_TYPE IS NOT NULL);;
CREATE VIEW mn_gis.v_forest_campgrounds AS SELECT FACILITY_N AS "name", st_x(st_centroid(st_transform(geom, 'EPSG:26915', 'EPSG:4326'))) AS latitude, st_y(st_centroid(st_transform(geom, 'EPSG:26915', 'EPSG:4326'))) AS longitude, 'MN' AS state_abbre, 'Minnesota' AS state, SITE_TYPE AS location_type, 5 AS data_source_key, GLOBALID AS orig_data_source_key, OGC_FID AS migration_primary_key, to_json(struct_pack(state_forest := STATE_FORE, pat_admin := PAT_ADMIN_)) AS attributes FROM mn_gis.state_forest_campgrounds_and_day_use_areas;;
CREATE VIEW mn_gis.v_location_types AS (SELECT DISTINCT UNIT_TYPE AS location_type FROM mn_gis.dnr_management_units_prk WHERE (UNIT_TYPE IS NOT NULL)) UNION (SELECT DISTINCT SITE_TYPE AS location_type FROM mn_gis.state_forest_campgrounds_and_day_use_areas WHERE (SITE_TYPE IS NOT NULL));;
CREATE VIEW mn_gis.v_management_units AS SELECT UNIT_NAME AS "name", st_x(st_centroid(st_transform(geom, 'EPSG:26915', 'EPSG:4326'))) AS latitude, st_y(st_centroid(st_transform(geom, 'EPSG:26915', 'EPSG:4326'))) AS longitude, 'MN' AS state_abbre, 'Minnesota' AS state, UNIT_TYPE AS location_type, 5 AS data_source_key, CAST(OGC_FID AS VARCHAR) AS orig_data_source_key, OGC_FID AS migration_primary_key, to_json(struct_pack(gis_acres := GIS_ACRES, legislative_id := LEGISLATIV)) AS attributes FROM mn_gis.dnr_management_units_prk;;
CREATE VIEW mn_gis_campsites.v_campsites AS SELECT CAMPING_UNIT_NAME AS "name", st_x(st_transform(Shape, 'EPSG:26915', 'EPSG:4326')) AS latitude, st_y(st_transform(Shape, 'EPSG:26915', 'EPSG:4326')) AS longitude, 'MN' AS state_abbre, 'Minnesota' AS state, COALESCE(CAMPING_UNIT_TYPE, 'Campsite') AS location_type, CAMPGROUND_NAME AS parent_campground, 6 AS data_source_key, STABLE_PROD_GUID AS orig_data_source_key, to_json(struct_pack(unit_type := CAMPING_UNIT_TYPE, description := CAMPING_UNIT_DESCRIP, loop := CAMPGROUND_LOOP_NAME, amps_30 := (AMPS_30_FLAG = 'Y'), amps_50 := (AMPS_50_FLAG = 'Y'), pad_length := SITE_PAD_LENGTH_FT, pad_width := SITE_PAD_WIDTH_FT, pad_type := SITE_PAD_TYPE_NAME, pull_through := (PULL_THROUGH_BACK_IN_FLAG = 'P'), tent_pad_dims := TENT_PAD_DIMENSIONS_FT_X_FT, picnic_table := (PICNIC_TABLE_FLAG = 'Y'), accessible := (ADA_ACCESSIBLE_FLAG = 'Y'), pets_allowed := (PETS_ALLOWED_FLAG = 'Y'), fire_ring := (FIRE_RING_FLAG = 'Y'), capacity_people := CAPACITY_PEOPLE, capacity_vehicles := CAPACITY_VEHICLES)) AS attributes FROM mn_gis_campsites.struc_parks_and_trails_campsites;;
CREATE VIEW mn_gis_campsites.v_campsite_campgrounds AS SELECT DISTINCT CAMPGROUND_NAME AS "name", 'MN' AS state_abbre, 'Minnesota' AS state, "first"(st_x(st_transform(Shape, 'EPSG:26915', 'EPSG:4326'))) AS latitude, "first"(st_y(st_transform(Shape, 'EPSG:26915', 'EPSG:4326'))) AS longitude, COALESCE(CAMPGROUND_TYPE_NAME, 'Campground') AS location_type, CONTAINING_MGMT_UNIT_NAME AS parent_mgmt_unit, 6 AS data_source_key, ('CAMPGROUND_' || lower(regexp_replace(CAMPGROUND_NAME, '[^a-z0-9]', '', 'g'))) AS orig_data_source_key, to_json(struct_pack(district := max(PAT_DISTRICT_NAME), region := max(DNR_REGION_NAME), county := max(COUNTY_NAME))) AS attributes FROM mn_gis_campsites.struc_parks_and_trails_campsites WHERE (CAMPGROUND_NAME IS NOT NULL) GROUP BY CAMPGROUND_NAME, CAMPGROUND_TYPE_NAME, CONTAINING_MGMT_UNIT_NAME;;
CREATE VIEW mn_gis_campsites.v_campsite_location_types AS (SELECT DISTINCT CAMPGROUND_TYPE_NAME AS location_type FROM mn_gis_campsites.struc_parks_and_trails_campsites WHERE (CAMPGROUND_TYPE_NAME IS NOT NULL)) UNION (SELECT DISTINCT CAMPING_UNIT_TYPE AS location_type FROM mn_gis_campsites.struc_parks_and_trails_campsites WHERE (CAMPING_UNIT_TYPE IS NOT NULL));;
CREATE VIEW nps.v_addresses AS SELECT id, parkId, campgroundId, postalCode AS postal_code, city, stateCode AS state_abbre, countryCode AS country_code, line1 AS address_line_1, line2 AS address_line_2, line3 AS address_line_3, "type" FROM nps.addresses;;
CREATE VIEW nps.v_address_types AS SELECT DISTINCT "type" AS address_type FROM nps.addresses WHERE ("type" IS NOT NULL);;
CREATE VIEW nps.v_campground_websites AS SELECT c.id AS campground_id, c.id AS migration_primary_key, c.regulationsUrl AS regulations_url, c.directionsUrl AS directions_url, c.reservationsUrl AS reservations_url, c.reservationsDescription AS reservations_description, p.url AS primary_url FROM nps.campgrounds AS c INNER JOIN nps.parks AS p ON ((p.parkCode = c.parkCode));;
CREATE VIEW nps.v_contact_emails AS SELECT id, parkId, campgroundId, emailAddress AS email_address, description, '' AS "type" FROM nps.contact_email_addresses;;
CREATE VIEW nps.v_contact_phones AS SELECT id, parkId, campgroundId, phoneNumber AS phone_number, "extension", description, "type" FROM nps.contact_phone_numbers;;
CREATE VIEW nps.v_locations AS SELECT id AS migration_primary_key, npsId AS orig_data_source_key, "name", description, latitude, longitude, states, COALESCE(weatherInfo, '') AS weather_info, COALESCE("nullif"(designation, ''), 'UNKNOWN') AS location_type, 1 AS data_source_key, to_json(struct_pack(park_code := p.parkCode, activities := (SELECT list(a."name" ORDER BY ac.ord) FROM unnest(p.activities) WITH ORDINALITY AS ac(id, ord) LEFT JOIN nps.activities AS a ON ((a.id = ac.id))), topics := (SELECT list(t."name" ORDER BY top.ord) FROM unnest(p.topics) WITH ORDINALITY AS top(id, ord) LEFT JOIN nps.topics AS t ON ((t.id = top.id))))) AS attributes FROM nps.parks AS p;;
CREATE VIEW nps.v_location_campgrounds AS SELECT c.npsId AS orig_data_source_key, c.id AS migration_primary_key, COALESCE(c.description, '') AS description, c.latitude, c.longitude, c."name", COALESCE(c.weatherOverview, '') AS weather_info, p.states AS states, 1 AS data_source_key, 6 AS location_type_key, to_json(struct_pack(wheel_chair_access := c.wheelChairAccess, internet_info := c.internetInfo, rv_allowed := c.rvAllowed, cell_phone_info := c.cellPhoneInfo, fire_stove_policy := c.fireStovePolicy, rv_max_length := c.rvMaxLength, additional_info := c.additionalInfo, trail_max_length := c.trailMaxLength, ada_info := c.adaInfo, rv_info := c.rvInfo, trail_allowed := c.trailAllowed, reservation_sites_first_come := c.reservationSitesFirstCome, access_roads := c.accessRoads, classifications := c.classifications, campsites_info := struct_pack(other := cc.other, "group" := cc."group", horse := cc.horse, total_sites := cc.totalSites, tent_only := cc.tentOnly, rv_only := cc.rvOnly, electrical_hookups := cc.electricalHookups, walk_boat_to := cc.walkBoatTo), campground_amenities := struct_pack(trash_recycling_collection := ca.trashRecyclingCollection, toilets := ca.toilets, internet_connectivity := ca.internetConnectivity, showers := ca.showers, cell_phone_reception := ca.cellPhoneReception, laundry := ca.laundry, amphitheater := ca.amphitheater, dump_station := ca.dumpStation, camp_store := ca.campStore, staff_or_volunteer_host_onsite := ca.staffOrVolunteerHostOnsite, potable_water := ca.potableWater, ice_available_for_sale := ca.iceAvailableForSale, firewood_for_sale := ca.firewoodForSale, food_storage_lockers := ca.foodStorageLockers), park_code := c.parkCode)) AS attributes FROM nps.campgrounds AS c INNER JOIN nps.campground_amenities AS ca ON ((c.id = ca.campgroundId)) INNER JOIN nps.campground_campsites AS cc ON ((c.id = cc.campgroundId)) INNER JOIN nps.parks AS p ON ((c.parkCode = p.parkCode));;
CREATE VIEW nps.v_location_types AS SELECT DISTINCT designation AS location_type FROM nps.parks WHERE ((designation IS NOT NULL) AND (designation != ''));;
CREATE VIEW nps.v_media AS SELECT * FROM ((SELECT id, parkId, campgroundId, credit, title, altText, caption, url, '' AS subtitle, 0 AS height, 0 AS width, 'photo' AS media_type FROM nps.images) UNION ALL (SELECT id, parkId, campgroundId, 'NPS' AS credit, title, '' AS altText, '' AS caption, url, '' AS subtitle, 0 AS height, 0 AS width, split_part("type", '/', 2) AS media_type FROM nps.multimedia WHERE (media_type !~~ '%galleries%'))) ORDER BY media_type;;
CREATE VIEW nps.v_operating_hours AS (SELECT id, parkId, campgroundId, "name", description, 'Regular' AS "type", NULL AS startDate, NULL AS endDate FROM nps.operating_hours) UNION ALL (SELECT oh.id, oh.parkId, oh.campgroundId, e."name", oh.description, 'Exception' AS "type", e.startDate, e.endDate FROM nps.operating_hours_exceptions AS e INNER JOIN nps.operating_hours AS oh ON ((e.operatingHoursId = oh.id)));;
CREATE VIEW nps.v_operating_hours_times AS WITH base_hours AS ((SELECT id AS operating_hours_id, parkId, campgroundId, 'Regular' AS "type", NULL AS startDate, NULL AS endDate, monday, tuesday, wednesday, thursday, friday, saturday, sunday FROM nps.operating_hours) UNION ALL (SELECT oh.id AS operating_hours_id, oh.parkId, oh.campgroundId, 'Exception' AS "type", e.startDate, e.endDate, e.monday, e.tuesday, e.wednesday, e.thursday, e.friday, e.saturday, e.sunday FROM nps.operating_hours_exceptions AS e INNER JOIN nps.operating_hours AS oh ON ((e.operatingHoursId = oh.id)))), unpivoted AS (SELECT operating_hours_id, parkId, campgroundId, "type", startDate, endDate, day_name, hours_text, CASE  WHEN ((day_name = 'monday')) THEN (1) WHEN ((day_name = 'tuesday')) THEN (2) WHEN ((day_name = 'wednesday')) THEN (3) WHEN ((day_name = 'thursday')) THEN (4) WHEN ((day_name = 'friday')) THEN (5) WHEN ((day_name = 'saturday')) THEN (6) WHEN ((day_name = 'sunday')) THEN (7) ELSE NULL END AS day_of_week FROM base_hours UNPIVOT (hours_text FOR day_name IN ('monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'))), parsed_times AS (SELECT *, regexp_extract(hours_text, '^(\d{1,2}):(\d{2})(AM|PM)', main.list_value('h', 'm', 'p')) AS s, regexp_extract(hours_text, '(\d{1,2}):(\d{2})(AM|PM)$', main.list_value('h', 'm', 'p')) AS e FROM unpivoted)SELECT operating_hours_id, parkId, campgroundId, "type", startDate, endDate, day_name, hours_text, day_of_week, CASE  WHEN ((hours_text = 'All Day')) THEN (0) WHEN (((s.h IS NOT NULL) AND (s.h != ''))) THEN ((TRY_CAST(s.h AS INTEGER) + CASE  WHEN (((s.p = 'PM') AND (s.h != '12'))) THEN (12) WHEN (((s.p = 'AM') AND (s.h = '12'))) THEN (-12) ELSE 0 END)) ELSE NULL END AS day_start_hour, CASE  WHEN ((hours_text = 'All Day')) THEN (0) WHEN (((s.m IS NOT NULL) AND (s.m != ''))) THEN (TRY_CAST(s.m AS INTEGER)) ELSE NULL END AS day_start_minute, CASE  WHEN ((hours_text = 'All Day')) THEN (23) WHEN (((e.h IS NOT NULL) AND (e.h != ''))) THEN ((TRY_CAST(e.h AS INTEGER) + CASE  WHEN (((e.p = 'PM') AND (e.h != '12'))) THEN (12) WHEN (((e.p = 'AM') AND (e.h = '12'))) THEN (-12) ELSE 0 END)) ELSE NULL END AS day_end_hour, CASE  WHEN ((hours_text = 'All Day')) THEN (59) WHEN (((e.m IS NOT NULL) AND (e.m != ''))) THEN (TRY_CAST(e.m AS INTEGER)) ELSE NULL END AS day_end_minute FROM parsed_times;;
CREATE VIEW nps.v_park_websites AS SELECT id AS park_id, id AS migration_primary_key, directionsInfo AS directions_info, directionsUrl AS directions_url, url AS primary_url FROM nps.parks;;
CREATE VIEW ridb.v_addresses AS (SELECT CAST(RecAreaID AS VARCHAR) AS orig_id, 'RECAREA' AS "source", COALESCE(PostalCode, '') AS postal_code, COALESCE(City, '') AS city, COALESCE(AddressStateCode, '') AS state_abbre, COALESCE(RecAreaStreetAddress1, '') AS line1, COALESCE(RecAreaStreetAddress2, '') AS line2, COALESCE(RecAreaStreetAddress3, '') AS line3, COALESCE(AddressCountryCode, '') AS country_code, RecAreaAddressType AS "type" FROM ridb.RecAreaAddresses_API_v1) UNION ALL (SELECT CAST(FacilityID AS VARCHAR) AS orig_id, 'FACILITY' AS "source", COALESCE(PostalCode, '') AS postal_code, COALESCE(City, '') AS city, COALESCE(AddressStateCode, '') AS state_abbre, COALESCE(FacilityStreetAddress1, '') AS line1, COALESCE(FacilityStreetAddress2, '') AS line2, COALESCE(FacilityStreetAddress3, '') AS line3, COALESCE(AddressCountryCode, '') AS country_code, FacilityAddressType AS "type" FROM ridb.FacilityAddresses_API_v1);;
CREATE VIEW ridb.v_aggregated_campsite_attributes AS SELECT CAST(EntityID AS VARCHAR) AS EntityID, json_group_object(AttributeName, CASE  WHEN (((AttributeValue IS NULL) OR (AttributeValue = ''))) THEN (to_json(CAST('t' AS BOOLEAN))) ELSE to_json(AttributeValue) END) AS attr_json FROM ridb.CampsiteAttributes_API_v1 WHERE (EntityType = 'Campsite') GROUP BY EntityID;;
CREATE VIEW ridb.v_aggregated_facility_activities AS SELECT CAST(ea.EntityID AS VARCHAR) AS EntityID, json_group_object(a.ActivityName, CASE  WHEN (((ea.ActivityDescription IS NULL) OR (ea.ActivityDescription = ''))) THEN (to_json(CAST('t' AS BOOLEAN))) ELSE to_json(ea.ActivityDescription) END) AS activities_json FROM ridb.EntityActivities_API_v1 AS ea INNER JOIN ridb.Activities_API_v1 AS a ON ((ea.ActivityID = a.ActivityID)) WHERE (ea.EntityType = 'Facility') GROUP BY ea.EntityID;;
CREATE VIEW ridb.v_aggregated_facility_tours AS WITH tour_links AS (SELECT CAST(CAST(EntityID AS BIGINT) AS VARCHAR) AS TourID, json_group_array(json_object('title', Title, 'url', URL, 'type', LinkType)) AS links FROM ridb.Links_API_v1 WHERE (EntityType = 'Tour') GROUP BY EntityID)SELECT CAST(t.FacilityID AS VARCHAR) AS FacilityID, json_group_array(json_object('tour_id', t.TourID, 'name', t.TourName, 'type', t.TourType, 'description', t.TourDescription, 'duration', t.TourDuration, 'accessible', t.TourAccessible, 'links', tl.links)) AS tours_json FROM ridb.Tours_API_v1 AS t LEFT JOIN tour_links AS tl ON ((CAST(t.TourID AS VARCHAR) = tl.TourID)) GROUP BY t.FacilityID;;
CREATE VIEW ridb.v_aggregated_rec_area_activities AS SELECT CAST(ea.EntityID AS VARCHAR) AS EntityID, json_group_object(a.ActivityName, CASE  WHEN (((ea.ActivityDescription IS NULL) OR (ea.ActivityDescription = ''))) THEN (to_json(CAST('t' AS BOOLEAN))) ELSE to_json(ea.ActivityDescription) END) AS activities_json FROM ridb.EntityActivities_API_v1 AS ea INNER JOIN ridb.Activities_API_v1 AS a ON ((ea.ActivityID = a.ActivityID)) WHERE (ea.EntityType = 'Rec Area') GROUP BY ea.EntityID;;
CREATE VIEW ridb.v_campsites AS SELECT COALESCE(v.CampsiteName, '') AS "name", COALESCE(v.CampsiteLatitude, 0.0) AS latitude, COALESCE(v.CampsiteLongitude, 0.0) AS longitude, '' AS directions_info, '' AS description, 'Campsite' AS location_type, 3 AS data_source_key, CAST(v.CampsiteID AS VARCHAR) AS orig_data_source_key, v.CampsiteID AS ridb_id, v.FacilityID AS parent_ridb_id, json_merge_patch(to_json(struct_pack(campsite_type := v.CampsiteType, type_of_use := v.TypeOfUse, loop := v.Loop, accessible := v.CampsiteAccessible, created_date := v.CreatedDate, last_updated := v.LastUpdatedDate)), agg.attr_json) AS attributes FROM ridb.Campsites_API_v1 AS v LEFT JOIN ridb.v_aggregated_campsite_attributes AS agg ON ((v.CampsiteID = agg.EntityID));;
CREATE VIEW ridb.v_facilities AS SELECT COALESCE(v.FacilityName, '') AS "name", COALESCE(v.FacilityLatitude, 0.0) AS latitude, COALESCE(v.FacilityLongitude, 0.0) AS longitude, COALESCE(v.FacilityDirections, '') AS directions_info, COALESCE(v.FacilityDescription, '') AS description, 'Facility' AS location_type, 3 AS data_source_key, CAST(v.FacilityID AS VARCHAR) AS orig_data_source_key, v.FacilityID AS ridb_id, v.ParentRecAreaID AS parent_ridb_id, to_json(struct_pack(facility_type := v.FacilityTypeDescription, stay_limit := v.StayLimit, keywords := v.Keywords, reservable := v.Reservable, enabled := v.Enabled, last_updated := v.LastUpdatedDate, activities := agg.activities_json, tours := t.tours_json)) AS attributes, v.FacilityPhone AS phone, v.FacilityEmail AS email, v.FacilityReservationURL AS reservation_url, v.FacilityMapURL AS map_url FROM ridb.Facilities_API_v1 AS v LEFT JOIN ridb.v_aggregated_facility_activities AS agg ON ((v.FacilityID = agg.EntityID)) LEFT JOIN ridb.v_aggregated_facility_tours AS t ON ((v.FacilityID = t.FacilityID));;
CREATE VIEW ridb.v_location_types AS (SELECT DISTINCT 'Recreation Area' AS location_type) UNION ((SELECT DISTINCT 'Facility' AS location_type) UNION (SELECT DISTINCT 'Campsite' AS location_type));;
CREATE VIEW ridb.v_rec_areas AS SELECT COALESCE(v.RecAreaName, '') AS "name", COALESCE(v.RecAreaLatitude, 0.0) AS latitude, COALESCE(v.RecAreaLongitude, 0.0) AS longitude, COALESCE(v.RecAreaDirections, '') AS directions_info, COALESCE(v.RecAreaDescription, '') AS description, 'Recreation Area' AS location_type, 3 AS data_source_key, CAST(v.RecAreaID AS VARCHAR) AS orig_data_source_key, v.RecAreaID AS ridb_id, to_json(struct_pack(org_rec_area_id := v.OrgRecAreaID, stay_limit := v.StayLimit, keywords := v.Keywords, reservable := v.Reservable, enabled := v.Enabled, last_updated := v.LastUpdatedDate, activities := agg.activities_json)) AS attributes, v.RecAreaPhone AS phone, v.RecAreaEmail AS email, v.RecAreaReservationURL AS reservation_url, v.RecAreaMapURL AS map_url FROM ridb.RecAreas_API_v1 AS v LEFT JOIN ridb.v_aggregated_rec_area_activities AS agg ON ((v.RecAreaID = agg.EntityID));;
CREATE VIEW ridb.v_websites AS (SELECT orig_data_source_key, reservation_url AS url, 'Reservations' AS "type", 'Official Reservation Website' AS description FROM ridb.v_rec_areas WHERE ((reservation_url IS NOT NULL) AND (reservation_url != ''))) UNION ALL (((SELECT orig_data_source_key, map_url AS url, 'Directions' AS "type", 'Map/Directions Website' AS description FROM ridb.v_rec_areas WHERE ((map_url IS NOT NULL) AND (map_url != ''))) UNION ALL (SELECT orig_data_source_key, reservation_url AS url, 'Reservations' AS "type", 'Official Reservation Website' AS description FROM ridb.v_facilities WHERE ((reservation_url IS NOT NULL) AND (reservation_url != '')))) UNION ALL ((SELECT orig_data_source_key, map_url AS url, 'Directions' AS "type", 'Map/Directions Website' AS description FROM ridb.v_facilities WHERE ((map_url IS NOT NULL) AND (map_url != ''))) UNION ALL (SELECT CAST(CAST(l.EntityID AS BIGINT) AS VARCHAR) AS orig_data_source_key, l.URL AS url, CASE  WHEN ((l.LinkType = 'Official Web Site')) THEN ('Primary') WHEN ((l.LinkType = 'Map')) THEN ('Directions') WHEN ((l.LinkType = 'Reservations')) THEN ('Reservations') ELSE l.LinkType END AS "type", COALESCE(l.Title, l.Description, '') AS description FROM ridb.Links_API_v1 AS l WHERE ((l.EntityType = 'Asset') AND (l.EntityID IS NOT NULL) AND (NOT isnan(l.EntityID)) AND (l.URL IS NOT NULL) AND (l.URL != '')))));;

